	(2287, 47, 'Acho que já mencionei, mas li seu livro.', 'I think I mentioned but I read your book', 1, 2, '2026-05-06 10:15:01', '2026-07-07 21:22:20', 31, 1, 4, NULL),
	(2288, 47, 'Meu querido amigo me disse que eu deveria relaxar de vez em quando.', 'My dear friend told me that I should relax every now and again', 1, 2, '2026-05-06 10:17:13', '2026-07-08 22:28:58', 31, 1, 4, NULL),
	(2289, 47, 'Eu estava esperando por isto.', 'I\'ve been waiting for this', 1, 2, '2026-05-06 10:18:13', '2026-07-12 13:08:48', 31, 1, 4, NULL),
	(2290, 47, 'Eu simplesmente senti que isso ia acontecer', 'I just felt like this was coming', 1, 2, '2026-05-06 10:18:56', '2026-07-07 21:22:06', 31, 1, 4, NULL),
	(2291, 47, 'Passagem de avião ', 'Plane ticket', 1, 2, '2026-05-06 23:20:37', '2026-07-09 21:04:19', 31, 1, 4, NULL),
	(2292, 47, 'Além do mais; além disso', 'Besides', 1, 2, '2026-05-07 10:26:07', '2026-07-09 21:04:13', 31, 1, 4, NULL),
	(2293, 47, 'Eu vou me dedicar', 'I will devoted myself', 1, 2, '2026-05-07 10:27:55', '2026-07-09 21:04:10', 31, 1, 4, NULL),
	(2294, 47, 'Eu estive', 'I\'ve been ', 1, 2, '2026-05-07 12:14:30', '2026-07-09 21:04:07', 31, 1, 4, NULL),
	(2295, 47, 'Eu estava tipo...', 'I was like', 1, 2, '2026-05-15 00:25:14', '2026-07-09 21:04:05', 31, 1, 4, NULL),
	(2296, 47, 'É isso que eu quero dizer.', 'This is I mean what I say', 1, 2, '2026-05-15 00:26:06', '2026-07-12 13:08:43', 31, 1, 4, NULL),
	(2297, 47, 'Vergonha', 'Shame', 1, 2, '2026-05-15 00:26:35', '2026-06-29 19:29:53', 31, 1, 4, NULL),
	(2298, 47, 'Nem liga pra mim, as vezes eu penso de um jeito engraçado ', 'Don\'t mind me, I think in a funny way sometimes', 1, 2, '2026-05-15 00:30:57', '2026-07-09 21:04:02', 31, 1, 4, NULL),
	(2299, 47, 'Eu já pedi/perguntei tantas vezes', 'I\'ve asked so many times', 1, 2, '2026-05-15 00:32:24', '2026-07-07 21:21:50', 31, 1, 4, NULL),
	(2300, 47, 'Naquela época eu não tinha experiência nem habilidades, mas agora tenho', 'I didn’t have the experience or skills back then, but now I do', 1, 2, '2026-05-15 00:33:22', '2026-07-08 22:28:38', 31, 1, 4, NULL),
	(2301, 47, 'É legal, não é?', 'It\'s cool, right?', 1, 2, '2026-05-20 16:14:20', '2026-06-29 19:29:51', 31, 1, 4, NULL),
	(2302, 47, 'Ela apagou minhas velas.', 'She blew out my candles', 1, 2, '2026-05-27 21:07:57', '2026-07-08 22:28:27', 31, 1, 4, NULL),
	(2303, 47, 'Um de vocês pode apagar a luz?', 'Will one of you hit the lights?', 1, 2, '2026-05-27 21:09:23', '2026-07-08 22:28:23', 31, 1, 4, NULL),
	(2304, 47, 'Quem você vai chamar?', 'Who ya gonna call?', 1, 2, '2026-05-27 21:10:18', '2026-07-12 13:08:38', 31, 1, 4, NULL),
	(2305, 47, 'Estou me preparando para trabalhar no exterior', 'I’m preparing myself to work abroad', 1, 2, '2026-07-01 12:25:52', '2026-07-12 15:31:16', 31, 1, 4, NULL),
	(2306, 47, 'Até ', 'Until', 1, 2, '2026-07-07 19:03:48', '2026-07-12 21:42:04', 31, 1, 4, NULL),
	(2307, 47, 'Eu não tenho mais vergonha disso', 'I\'m not embarrassed about that anymore', 1, 2, '2026-07-07 19:09:01', '2026-07-13 19:28:47', 31, 1, 4, NULL),
	(2308, 47, 'Se eu notar esses erros, significa que eu melhorei', 'if I notice those mostakes, it means I improved', 1, 2, '2026-07-07 21:17:22', '2026-07-07 21:17:44', 31, 0, 1, NULL),
	(2309, 47, 'Se eu notar esses erros, significa que eu melhorei', 'if I notice those mistakes, it means I improved', 1, 2, '2026-07-07 21:18:28', '2026-07-13 19:26:59', 31, 1, 2, NULL),
	(2310, 63, 'Eu quero viajar com você essa semana', 'I want to travel with you this week', 1, 2, '2026-07-12 21:39:41', '2026-07-12 21:39:41', 72, 1, 1, NULL),
	(2311, 63, 'Como compro a passagem de avião?', 'How do I buy a plane ticket?', 1, 2, '2026-07-12 21:39:41', '2026-07-12 21:39:41', 72, 1, 1, NULL),
	(2312, 47, 'Foi assim que eu aprendi ingles', 'That\'s how I learned English', 1, 2, '2026-07-13 16:17:42', '2026-07-13 19:28:34', 31, 1, 2, NULL),
	(2313, 47, 'Eu sei que isso não vai acontecer ', 'I know it wont happen', 1, 2, '2026-07-13 16:56:06', '2026-07-13 19:28:24', 31, 1, 2, NULL),
	(2314, 47, 'Eu sei que isso levará tempo ', 'I know It Will take time', 1, 2, '2026-07-13 19:32:06', '2026-07-13 19:32:06', 31, 1, 1, NULL),
	(2315, 47, 'Quiero viajar a España el próximo verano', 'I want to travel to Spain next summer', 1, 3, '2026-07-14 14:10:20', '2026-07-14 17:21:37', 74, 1, 1, NULL),
	(2316, 47, 'Siempre llevo mi pasaporte y mi equipaje de mano', 'I always carry my passport and my carry-on luggage', 1, 3, '2026-07-14 14:10:45', '2026-07-14 17:21:50', 74, 1, 1, NULL),
	(2317, 47, '¿A qué hora sale el vuelo hacia Nueva York?', 'What time does the flight to New York depart?', 1, 3, '2026-07-14 14:11:04', '2026-07-14 17:21:56', 74, 1, 1, NULL),
	(2318, 47, 'Reservamos un hotel cerca de la playa para las vacaciones', 'We booked a hotel near the beach for our vacation', 1, 3, '2026-07-14 14:11:20', '2026-07-14 17:22:01', 74, 1, 1, NULL),
	(2319, 47, 'Me encanta conocer nuevos países y descubrir diferentes culturas', 'I love visiting new countries and discovering different cultures', 1, 3, '2026-07-14 14:11:38', '2026-07-14 17:22:06', 74, 1, 1, NULL),
	(2320, 47, 'Je rêve de voyager autour du monde', 'I dream of traveling around the world', 1, 4, '2026-07-14 14:14:40', '2026-07-14 17:22:17', 75, 1, 1, NULL),
	(2321, 47, 'Nous avons réservé un hôtel près de la plage', 'We booked a hotel near the beach', 1, 4, '2026-07-14 14:14:56', '2026-07-14 17:22:20', 75, 1, 1, NULL),
	(2322, 47, 'À quelle heure part le train pour Paris ?', 'What time does the train to Paris leave?', 1, 4, '2026-07-14 14:15:16', '2026-07-14 17:22:24', 75, 1, 1, NULL),
	(2323, 47, 'J\'emporte toujours mon passeport et mes billets', 'I always bring my passport and my tickets', 1, 4, '2026-07-14 14:15:33', '2026-07-14 17:22:27', 75, 1, 1, NULL),
	(2324, 47, 'Les voyages permettent de découvrir de nouvelles cultures', 'Traveling allows you to discover new cultures', 1, 4, '2026-07-14 14:15:54', '2026-07-14 17:22:31', 75, 1, 1, NULL),
